-- 2026-07-08: THE EYE + eye-walker 5-defect pass on magnetic_flux_loop (status=OPEN).
-- Generated by src/scripts/_seed_engine_bug_queue_magnetic_flux_loop_eye_pass.ts — idempotent.

INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('mfl_control_panel_slider_desync', 'magnetic_flux_loop: slider handle + numeric label stay pinned at authored defaults (B=0.80T/A=1.00m2/theta=0deg) on every state (S2-S5) AND the live explore state S6, while the physics readout box shows the live/tweened value', 'CRITICAL', 'peter_parker:renderer_primitives', 'applyMagneticFluxLoopState() writes the slider DOM (value + label text) exactly once, at state-entry, from the STATE default (defB/defA/defTh) — never again. updateMagneticFluxLoopFrame() reads mflControlValueAt() every frame to drive the loop pose + Phi readout (idle-sweep-or-drag), but never writes that live/tweened value back into the #mfl_b_slider / #mfl_a_slider / #mfl_theta_slider DOM elements or their _val label spans. Reproducing in S6 (the free explore state) too rules out "scripted idle-sweep only" — even a manually dragged slider''s OWN readout box (which reads mflControlValueAt''s dragged branch) is correct, but a SECOND state-entry re-seeds the widget back to the default without re-syncing after any subsequent idle-sweep frame, and the idle-sweep path never touches the widget at all.', 'Any field_3d dedicated slider panel whose live value can change on a per-frame basis (idle sweep, tween, drag) MUST sync BOTH its handle (input.value) and its numeric label span from the SAME live value the frame-update function computes for the readout — every frame, not only on state-entry or on the widget''s own input event. A widget and its own readout panel must never be able to show different numbers for the same variable.', 'manual', 'On any magnetic_flux_loop state with a live control (S2-S6), after ~2s let the idle sweep run, then compare the #mfl_readout B/A/theta numbers against the #mfl_b_slider/#mfl_a_slider/#mfl_theta_slider handle position + their _val label text — they must match at every sampled frame.', 'OPEN', ARRAY['magnetic_flux'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-08_magnetic_flux_loop_eye_pass', 'incident'),
('mfl_state1_zero_motion_reveal', 'magnetic_flux_loop STATE_1 (lines_through_window) renders 27 byte-identical frames across ~26s with ZERO motion, despite narration "the tally builds one line at a time" and mode:guided/controls:[] (fully engine-driven motion)', 'CRITICAL', 'peter_parker:renderer_primitives', 'buildMagneticFluxLoop() seeds every mfl_field_line ArrowHelper visible with a fixed opacity from config.field_lines.opacity, and updateMagneticFluxLoopFrame()''s density/tint pass only fires proportional to the live B value (via visCount) — it never staggers a sequential reveal for a state with controls:[] (nothing to sweep), so a state with no live control renders the fully-populated lattice motionless from frame 1. No per-line reveal timeline existed for this scenario at all.', 'A field_3d state authored controls:[] (guided, nothing user-facing to drive) is NOT exempt from Rule 26/32 motion — if the narration describes a build-up, the renderer must run its OWN pure-function-of-state-clock reveal timeline. Every guided state must be checked for byte-identical consecutive frames across its full duration before declaring a scenario done; a 0-motion opening state is the worst-case regression.', 'manual', 'On magnetic_flux_loop STATE_1 dense frames, consecutive frames across the full state duration must NOT be byte-identical after the first ~0.5s — lines must appear on a staggered reveal, and the Phi/tally counter text must change at least once after the last line lands.', 'OPEN', ARRAY['magnetic_flux'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-08_magnetic_flux_loop_eye_pass', 'incident'),
('mfl_dual_glow_focal_field_lines', 'magnetic_flux_loop S1/S2/S3: 2 field lines glow bright simultaneously — Rule 32e (exactly ONE glow focal at any instant) violated', 'MODERATE', 'peter_parker:renderer_primitives', 'updateMagneticFluxLoopFrame()''s per-line opacity/tint pass computes ''slotOn'' from a coarse (Math.abs(gridY)+Math.abs(gridZ)) <= threshold test against the 4x4 MFL_LINE_GRID, which admits MULTIPLE lattice slots at the same Manhattan-distance tier simultaneously (the grid has symmetric slots at equal |y|+|z|) — so the "brightened" set is never exactly one line, it is a whole distance-tier ring.', 'A single-focal reveal/highlight pass over a lattice must rank candidates with a STRICT total order (index/sequence number, not a distance metric with ties) and light exactly the top-1 (or a designated representative), never an entire tied tier. Applies to any field_3d "one thing glows" beat (S1 newest-landed, S2 densest-cluster representative, S3 rim-not-lines).', 'manual', 'On magnetic_flux_loop S1/S2/S3 dense frames, count field-line ArrowHelpers whose material.opacity is within 5% of the frame-max opacity — must be exactly 1 (S1: the newest-landed line; S2: one densest-cluster representative; S3: none — the rim itself is the focal, no line should out-glow it).', 'OPEN', ARRAY['magnetic_flux'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-08_magnetic_flux_loop_eye_pass', 'incident'),
('mfl_state3_enclosed_count_not_scaling', 'magnetic_flux_loop S3: loop rim visibly grows ~40->330px as A triples, but the enclosed/highlighted line count stays fixed at 2 lines — "more lines" is not visually reinforced by the growing loop', 'MODERATE', 'peter_parker:renderer_primitives', 'updateMagneticFluxLoopFrame()''s ''through'' test (Math.abs(gridY) < footprint && Math.abs(gridZ) < footprint) uses ''footprint'' correctly derived from the live area (MFL_LOOP_SCALE*sqrt(A)/2), but the fixed 4x4 MFL_LINE_GRID only has 2 lattice slots close enough to the origin to ever cross that threshold across the authored A range (0.25-4.0 m2) — the grid spacing (0.44 world units between rings) is coarser than the footprint''s growth (0.25-0.8 world units), so no additional slot is ever captured as A grows.', 'When a highlighted/enclosed subset of a fixed lattice is meant to visibly scale with a growing geometric footprint, the lattice spacing must be fine enough (or the footprint growth range wide enough) that the enclosed COUNT actually changes across the full authored slider range — verify by sampling the count at range.min, range.mid, range.max before shipping, not just checking the boundary math is directionally correct.', 'manual', 'On magnetic_flux_loop S3, sample the through-loop highlighted line count at A=0.25, A=1.0 (default), A=4.0 (S3 theta_range/controls default) — the count must strictly increase (or the loop must visibly grow to engulf a materially larger fraction of the on-screen lattice) across that range, never stay pinned at 2.', 'OPEN', ARRAY['magnetic_flux'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-08_magnetic_flux_loop_eye_pass', 'incident'),
('mfl_state4_projection_shadow_weak_shrink', 'magnetic_flux_loop S4: the A.cos(theta) amber projection-shadow only shrinks ~8% in height between theta=0 and theta=90deg in the captured camera framing, weakening the PRIMARY aha (Phi readout already correctly hits 0.00 at theta=90 but the shadow does not visually match)', 'MODERATE', 'peter_parker:renderer_primitives', 'updateMagneticFluxLoopFrame()''s projection block scales the shadow by sc = Math.sqrt(effCos) * halfWidth, i.e. a RADIUS/half-width scale — for a camera framing where the shadow''s on-screen HEIGHT is dominated by a near-constant base size plus a small variable term, sqrt(cos) only reaches its steep collapse very close to theta=90 (sqrt(cos80deg)=~0.42, not visually dramatic against the loop''s own unchanged apparent size), so across the authored S4 theta_range [0,90] the shrink reads as subtle rather than "collapsing to a hairline".', 'A shrink-to-zero visual sold as the PRIMARY aha of a state must be driven directly off the SAME effective-area quantity the numeric readout reports (not a geometric proxy like sqrt(cos) chosen for a different scenario''s disc framing) and must be verified to visibly collapse toward a hairline (near-zero screen height) at the state''s own theta_range maximum, not just directionally shrink.', 'manual', 'On magnetic_flux_loop S4 dense frames, the projection shadow''s on-screen pixel height at theta=90 (theta_range max) must be <=10% of its height at theta=0, while the B field-line lattice remains fully visible/unpinned in strength throughout (the B-pinned/A.cos-theta-shrinks contrast is the aha).', 'OPEN', ARRAY['magnetic_flux'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-08_magnetic_flux_loop_eye_pass', 'incident')
